import React from "react";
import Container from 'react-bootstrap/Container';
import Row from 'react-bootstrap/Row';
import Col from 'react-bootstrap/Col';
import certi from "./images/certi.jpg"

function CertGallery(){
    return(
        <Container fluid>
            <Row>
                <Col xs={12} md={7} className="lb d-sm-block d-none">
                    <img src={certi} alt=" " className="slideimg"/>
                </Col>
                <Col xs={12} md={5} className="lb">
                <p className="selfdec">Certifications</p>
                <ul style={{marginTop:"35px",}}>
                    <li className="acheive">CRASH COURSE ON PYTHON,(Coursera)-2021</li>
                    <li className="acheive">CRASH COURSE ON PYTHON,(Coursera)-2021</li>
                    <li className="acheive">Introduction to IoT,(Cisco)-2020</li>
                    <li className="acheive">Descriptive Statistics with R software,(NPTEL)-2019</li>
                    <li className="acheive">PYTHON for Datascience,(NPTEL)-2020</li>
                    <li className="acheive">Leadership and Emotional Intelligece,(Coursera)-2022</li>
                    <li className="acheive">JavaScript Beigner's Bootcamp,(Udemy)-2019</li>
                  
                </ul>
                
                </Col>
                
            </Row>
        </Container>

    );
};


export default CertGallery;