import React from "react";
import Container from 'react-bootstrap/Container';
import Row from 'react-bootstrap/Row';
import Col from 'react-bootstrap/Col';
import contact from "./images/contact.jpg"
import Button from 'react-bootstrap/Button';
import Form from 'react-bootstrap/Form';

function Contact(){
    return(
        <Container fluid>
            <Row>
                <Col xs={12} md={5} className="lb">
                <p className="selfdec">Contact Me</p>
                <Form action="mailto:sabarishkumar742@gmail.com" method="post" enctype="text/plain">
                    <Form.Group>
                        <Form.Label>Name:</Form.Label>
                        <Form.Control type="text" placeholder="Enter your Name" name="name"></Form.Control>
                    </Form.Group>
                    <Form.Group>
                        <Form.Label>E-mail:</Form.Label>
                        <Form.Control type="text" placeholder="Enter your E-mail" name="mail"></Form.Control>
                    </Form.Group>
                    <Form.Group>
                        <Form.Label>Message:</Form.Label>
                        <Form.Control type="text"  name="comment" style={{height:"200px"}}></Form.Control>
                    </Form.Group>
                    <div>
                    <Button variant="primary" type="submit" style={{marginTop:"15px",width:"100px"}}>Send</Button>
                    <Button variant="danger" type="reset" style={{marginTop:"15px",width:"100px",marginLeft:"10px"}}>Reset</Button>
                    </div>
                </Form>
                
                </Col>
                <Col xs={12} md={7} className="lb d-sm-block d-none">
                    <img src={contact} alt=" " className="slideimg"/>
                </Col>
            </Row>
            <center>Designed and Developed by SABARISHKUMAR</center>
        </Container>

    );
};


export default Contact;