import React from "react";
import Container from 'react-bootstrap/Container';
import Row from 'react-bootstrap/Row';
import Col from 'react-bootstrap/Col';
import acheive from "./images/acheive.jpg"

function Acheivement(){
    return(
        <Container fluid>
            <Row>
                <Col xs={12} md={5} className="lb">
                <p className="selfdec">Acheivements</p>
                <ul style={{marginTop:"35px",}}>
                    <li className="acheive">Attended one day International Workshop on “Building a Face Recognition Application using Python” organized by GUVI</li>
                    <li className="acheive">Winner of “TSS Coding Challenge” coding-competition conducted by TECHGIG</li>
                    <li className="acheive">Winner of “Open Round Coding Contest” conducted by TECHGIG</li>
                    <li className="acheive">Awarded a “Gold Badge” in Python Programming by HACKER RANK</li>
                </ul>
                
                </Col>
                <Col xs={12} md={7} className="lb d-sm-block d-none">
                    <img src={acheive} alt=" " className="slideimg"/>
                </Col>
            </Row>
        </Container>

    );
};

export default Acheivement;